// Load script setelah DOM berhasil diload
$(function () {
    let formCekEdit; // global untuk tracking

    // Pasang csrf token untuk semua permintaan ajax
    $.ajaxSetup({
        headers: {
            "X-CSRF-TOKEN": $('meta[name="csrf-token"]').attr("content"),
        },
    });

    // Buka tutup input password
    $(document).on("click", ".toggle-password", function () {
        let $allInputs = $(
            "input[type='password'], input[type='text'][data-password='true']"
        );

        if ($allInputs.first().attr("type") === "password") {
            // ubah semua jadi text
            $allInputs.attr("type", "text").attr("data-password", "true");
            $(".toggle-password i")
                .removeClass("bi-eye-fill")
                .addClass("bi-eye-slash-fill");
        } else {
            // ubah semua jadi password
            $allInputs.attr("type", "password");
            $(".toggle-password i")
                .removeClass("bi-eye-slash-fill")
                .addClass("bi-eye-fill");
        }
    });

    // Fungsi load statisik user
    function loadStats() {
        $.get(window.routes.statisticUser, function (res) {
            $(".stat-value").each(function () {
                let key = $(this).data("key");
                if (res[key] !== undefined) {
                    $(this).text(res[key]);
                }
            });
            $(".overlay.dark").fadeOut();
        });
    }

    // Form Tambah user
    $("#formAddUser").validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                name: { required: true, minlength: 3, maxlength: 30 },
                email: { required: true, email: true, customEmail: true },
                password: { required: true, minlength: 8 },
                password_confirmation: {
                    required: true,
                    equalTo: "#formAddUser input[name='password']",
                },
                perusahaan: { minlength: 3, maxlength: 30 },
                whatsapp: { number: true, minlength: 8, maxlength: 15 },
                telegram: { number: true, minlength: 8, maxlength: 15 },
                alamat: { minlength: 5, maxlength: 100 },
            },
            submitHandler: function (form) {
                let $btnSubmit = $(form).find("button[type=submit]");
                let $btnCancle = $(form).find(".btn-danger");
                let $btnLoading = $(form).find("#btn-loading");

                $btnSubmit.hide();
                $btnCancle.hide();
                $btnLoading.show();

                // Melakukan request ajax untuk tambah user
                $.ajax({
                    url: $(form).attr("action"),
                    type: "POST",
                    data: $(form).serialize(),
                    success: function (res) {
                        if (res.success) {
                            $("#modalAddUser").modal("hide");
                            $("#tableUserList").DataTable().ajax.reload();
                            Swal.fire("Sukses", res.message, "success");
                            $(form)[0].reset();
                            $(form).validate().resetForm();
                            $(form).find(".is-valid").removeClass("is-valid");

                            loadStats();
                        }
                    },
                    error: function (xhr) {
                        if (xhr.status === 422) {
                            let errors = xhr.responseJSON.errors;
                            if (errors) {
                                $(form).validate().showErrors(errors);
                            }
                        }

                        Swal.fire(
                            "Validasi Gagal!",
                            "Silahkan periksa kembali input Anda",
                            "error"
                        );
                    },
                    complete: function () {
                        $btnLoading.hide();
                        $btnSubmit.show();
                        $btnCancle.show();
                    },
                });
                return false;
            },
        })
    );

    // Form Ubah User
    $("#formEditUser").validate(
        $.extend(FormHelper.validasiForm(), {
            rules: {
                name: { required: true, minlength: 3, maxlength: 30 },
                email: { required: true, email: true, customEmail: true },
                password: { minlength: 8 },
                password_confirmation: {
                    equalTo: "#formEditUser input[name='password']",
                },
                perusahaan: { minlength: 3, maxlength: 30 },
                whatsapp: { number: true, minlength: 8, maxlength: 15 },
                telegram: { number: true, minlength: 8, maxlength: 15 },
                alamat: { minlength: 5, maxlength: 100 },
            },
            submitHandler: function (form) {
                let $btnSubmit = $(form).find("button[type=submit]");
                let $btnCancle = $(form).find(".btn-danger");
                let $btnLoading = $(form).find("#btn-loading");

                // cek perubahan dari data semula
                if (formCekEdit && !formCekEdit.isChanged()) {
                    return false;
                }

                $btnSubmit.hide();
                $btnCancle.hide();
                $btnLoading.show();

                // Melakukan request ajax untuk pembaruan data user
                $.ajax({
                    url: $(form).attr("action"),
                    type: "POST",
                    data: $(form).serialize(),
                    success: function (res) {
                        if (res.success) {
                            $("#modalEditUser").modal("hide");
                            $("#tableUserList").DataTable().ajax.reload();
                            Swal.fire("Sukses", res.message, "success");
                            $(form)[0].reset();
                            $(form).validate().resetForm();
                            $(form).find(".is-valid").removeClass("is-valid");

                            loadStats();
                        }
                    },
                    error: function (xhr) {
                        if (xhr.status === 422) {
                            let errors = xhr.responseJSON.errors;
                            if (errors) {
                                $(form).validate().showErrors(errors);
                            }
                        }

                        Swal.fire(
                            "Validasi Gagal!",
                            "Silahkan periksa kembali input Anda",
                            "error"
                        );
                    },
                    complete: function () {
                        $btnLoading.hide();
                        $btnSubmit.show();
                        $btnCancle.show();
                    },
                });
                return false;
            },
        })
    );

    // Ambil user berdasarkan id
    $(document).on(
        "click",
        '#tableUserList button[data-target="#modalEditUser"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getUser.replace(":id", id);
            let $form = $("#formEditUser");

            $.get(url)
                .done(function (res) {
                    let user = res.user;

                    $form[0].reset();
                    $form.validate().resetForm();
                    $form
                        .find(".is-valid, .is-invalid")
                        .removeClass("is-valid is-invalid");

                    // Mendefinisikan endpoint route untuk pembaruan user    
                    $form.attr(
                        "action",
                        window.routes.updateUser.replace(":id", id)
                    );

                    $("#edit_name").val(user.name);
                    $("#edit_email").val(user.email);
                    $("#edit_aktivasi").val(user.active ? "Aktif" : "Nonaktif");
                    $("#edit_role").val(user.role);
                    $("#edit_password, #edit_password_confirmation").val("");

                    if (user.profile) {
                        $("#edit_perusahaan").val(
                            user.profile.perusahaan || ""
                        );
                        $("#edit_whatsapp").val(user.profile.whatsapp || "");
                        $("#edit_telegram").val(user.profile.telegram || "");
                        $("#edit_alamat").val(user.profile.alamat || "");
                    } else {
                        $(
                            "#edit_perusahaan, #edit_whatsapp, #edit_telegram, #edit_alamat"
                        ).val("");
                    }

                    $("#modalEditUser").modal("show");

                    // reset tracker perubahan form
                    formCekEdit = FormHelper.cekFormData("#formEditUser");
                })
                .fail(function (xhr) {
                    // ambil pesan error dari response JSON (misalnya dari handleException)
                    let message =
                        (xhr.responseJSON && xhr.responseJSON.message) ||
                        "Terjadi kesalahan saat mengambil data user.";

                    // tampilkan SweetAlert error
                    Swal.fire({
                        icon: "error",
                        title: "Gagal memuat data!",
                        text: message,
                    });
                });
        }
    );


    // Inisialisasi data tabel user-list
    TableHelper.init("#tableUserList", {
        ajax: window.routes.dataTable,
        order: [[1, "asc"]],
        filters: [3, 4], // filter untuk Status & Role
        buttons: [
            {
                text: "Add",
                attr: {
                    "data-target": "#modalAddUser",
                    "data-toggle": "modal",
                },
            },
            { text: "Excel" },
        ],
        columns: [
            {
                data: "id",
                title: "ID",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            { 
                data: "name", 
                title: "Nama User", 
                className: "dt-head-center", 
                orderable: true,
            },
            {
                data: "email",
                title: "Alamat Email",
                className: "dt-head-center",
                orderable: false,
            },
            {
                data: "status",
                title: "Status",
                className: "dt-head-center dt-body-center",
                orderable: true,
                render: {
                    _: (statusValue) => (statusValue ? "Aktif" : "Non aktif"), // representasi data yang tampil untuk semua versi render
                    display: (
                        statusValue // representasi data yang tampil untuk versi tampilan di browser saja
                    ) =>
                        statusValue
                            ? '<span class="lencana bg-primary">Aktif</span>'
                            : '<span class="lencana bg-danger">Non aktif</span>',
                },
            },
            {
                data: "role",
                title: "Hak Akses",
                className: "dt-head-center dt-body-center",
                orderable: true,
            },
            {
                data: "last_login_at",
                title: "Terakhir Aktif",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "created_at",
                title: "Dibuat",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: "updated_at",
                title: "Diubah",
                className: "dt-head-center dt-body-center",
                orderable: false,
                render: TableHelper.tabelTanggalWaktu,
            },
            {
                data: null,
                title: "Aksi",
                orderable: false,
                className: "dt-head-center dt-body-center",
                render: (data, type, row) =>
                    type === "display"
                        ? `<div class="btn-group" role="group">
                                <button class="btn btn-sm btn-dark btn-edit" data-id="${row.id}" data-toggle="modal" data-target="#modalEditUser">Edit</button>
                                <button class="btn btn-sm btn-success btn-profile" data-id="${row.id}">Profil</button>
                           </div>`
                        : "",
            },
        ],
    });

    // Panggil statistik user saat halaman dimuat
    loadStats();
});
